         int total = 0;
         for (int i = 0; i < _wordLengths.Count; i++)
             total += _wordLengths[i];
         return (double)total / _wordLengths.Count;
     }

     /// <summary>
     /// Builds a histogram of word lengths. Index i contains the count
     /// of words with length i.
     /// </summary>
