using System.Diagnostics;
using System.Runtime.CompilerServices;
using TextAnalysis;

// Setup
var words = new[] { "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
    "performance", "benchmarking", "analysis", "comprehensive", "evaluation", "framework",
    "infrastructure", "implementation", "documentation", "specification", "configuration" };
var rng = new Random(42);
var sb = new System.Text.StringBuilder();
for (int i = 0; i < 10_000; i++)
{
    if (i > 0) sb.Append(' ');
    sb.Append(words[rng.Next(words.Length)]);
}
var analyzer = new TextAnalyzer(sb.ToString());

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Words: {analyzer.WordCount:N0}");
Console.WriteLine();

// Warmup and benchmark each method
Benchmark("AverageWordLength", () => analyzer.AverageWordLength());
Benchmark("WordLengthHistogram", () => analyzer.WordLengthHistogram());
Benchmark("UniqueWordCount", () => analyzer.UniqueWordCount());

static void Benchmark(string name, Func<object?> action)
{
    const int warmupIterations = 500;
    const int benchIterations = 10_000;

    // Warmup
    for (int i = 0; i < warmupIterations; i++)
        action();

    // Collect multiple runs for statistics
    var times = new double[20];
    for (int run = 0; run < times.Length; run++)
    {
        var sw = Stopwatch.StartNew();
        for (int i = 0; i < benchIterations; i++)
            action();
        sw.Stop();
        times[run] = sw.Elapsed.TotalNanoseconds / benchIterations;
    }

    Array.Sort(times);
    // Use median and IQR for robust statistics
    double median = times[times.Length / 2];
    double q1 = times[times.Length / 4];
    double q3 = times[3 * times.Length / 4];
    double mean = times.Average();
    double min = times[0];

    Console.WriteLine($"{name,-25} | Mean: {mean,10:F2} ns | Median: {median,10:F2} ns | Min: {min,10:F2} ns | Q1-Q3: [{q1:F2} - {q3:F2}] ns");
}
